package com.training.vulnapp;

import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.text.TextUtils;
import android.util.Log;
import androidx.appcompat.app.AppCompatActivity;
import java.util.regex.Pattern;

public class ProfileActivity extends AppCompatActivity {

    private static final int MAX_NAME_LEN = 32;
    private static final Pattern NAME_PATTERN = Pattern.compile("^[a-zA-Z0-9_.-]+$");
    private SQLiteDatabase database;

    private void searchUser(String username) {
        // FIXED: Validate input before use
        if (username == null || username.isEmpty()) {
            showError("Username cannot be empty");
            return;
        }
        if (username.length() > MAX_NAME_LEN) {
            showError("Username too long");
            return;
        }
        if (!NAME_PATTERN.matcher(username).matches()) {
            showError("Username contains invalid characters");
            return;
        }

        // FIXED: Parameterized query prevents SQL injection
        Cursor cursor = database.rawQuery(
            "SELECT * FROM users WHERE username = ?",
            new String[]{ username }
        );
        Log.d("DB", "User lookup executed"); // No query details in log
    }

    private void setDisplayName(String name) {
        if (name == null || name.length() > MAX_NAME_LEN) return;
        // FIXED: Encode HTML entities if used in WebView contexts
        tvDisplayName.setText(TextUtils.htmlEncode(name));
    }

    private void saveAge(String ageInput) {
        // FIXED: Handle parse error and validate range
        try {
            int age = Integer.parseInt(ageInput.trim());
            if (age < 1 || age > 150) {
                showError("Age out of valid range");
                return;
            }
            storeAge(age);
        } catch (NumberFormatException e) {
            showError("Age must be a numeric value");
        }
    }
}

