// FIXED: Native code only validates input format.
// Real authorization decision happens on the backend.
// No hardcoded secret in native code.
#include <jni.h>
#include <string>

extern "C" JNIEXPORT jboolean JNICALL
Java_com_training_vulnapp_MainActivity_checkLicenseFormat(
        JNIEnv* env,
        jobject /* this */,
        jstring input) {

    const char* inputCStr = env->GetStringUTFChars(input, nullptr);
    if (inputCStr == nullptr) return JNI_FALSE;

    std::string s(inputCStr);
    env->ReleaseStringUTFChars(input, inputCStr);

    // Only validate format: 10-50 chars, alphanumeric + dash
    // Does NOT check if token is actually valid — backend does that
    if (s.length() < 10 || s.length() > 50) return JNI_FALSE;
    for (char c : s) {
        if (!isalnum((unsigned char)c) && c != '-') return JNI_FALSE;
    }
    return JNI_TRUE; // Format OK — still needs backend verification
}

